import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import FacultyLayout from "../../layouts/FacultyLayout";

function FacultyDashboard() {

  const navigate = useNavigate();

  const { user } = useAuth();

  return (

    <FacultyLayout>

      {/* Welcome Banner */}

      <div
        style={{
          background:
            "linear-gradient(135deg,#2563eb,#1e40af)",
          color: "white",
          padding: "30px",
          borderRadius: "15px",
          marginBottom: "30px"
        }}
      >
        <h1
          style={{
            margin: 0
          }}
        >
          Welcome, {user?.name}
        </h1>

        <p
          style={{
            marginTop: "10px",
            opacity: 0.9
          }}
        >
          SRIHER IQAC Faculty Dashboard
        </p>
      </div>

      {/* Statistics */}

      <div
        style={{
          display: "grid",
          gridTemplateColumns:
            "repeat(auto-fit,minmax(250px,1fr))",
          gap: "20px",
          marginBottom: "40px"
        }}
      >

        <div className="stat-card">
          <h2>0</h2>
          <p>Total Submissions</p>
        </div>

        <div className="stat-card">
          <h2>0</h2>
          <p>Draft Reports</p>
        </div>

        <div className="stat-card">
          <h2>0</h2>
          <p>Pending Approval</p>
        </div>

      </div>

      {/* Quick Actions */}

      <h2
        style={{
          marginBottom: "20px"
        }}
      >
        Quick Actions
      </h2>

      <div
        style={{
          display: "grid",
          gridTemplateColumns:
            "repeat(auto-fit,minmax(280px,1fr))",
          gap: "20px"
        }}
      >

        <div className="action-card">

          <h3>
            📝 Questionnaire
          </h3>

          <p>
            Fill quarterly IQAC questionnaire
          </p>

          <button
            onClick={() =>
              navigate(
                "/faculty/questionnaire"
              )
            }
          >
            Open
          </button>

        </div>

        <div className="action-card">

          <h3>
            📂 My Submissions
          </h3>

          <p>
            View all submitted reports
          </p>

          <button
            onClick={() =>
              navigate(
                "/faculty/submissions"
              )
            }
          >
            View
          </button>

        </div>

        <div className="action-card">

          <h3>
            👤 Profile
          </h3>

          <p>
            Update your profile details
          </p>

          <button
            onClick={() =>
              navigate("/profile")
            }
          >
            Open
          </button>

        </div>

      </div>

      <style>
        {`
        .stat-card{
          background:white;
          padding:25px;
          border-radius:15px;
          box-shadow:0 4px 15px rgba(0,0,0,0.08);
          text-align:center;
        }

        .stat-card h2{
          color:#2563eb;
          margin:0;
          font-size:32px;
        }

        .action-card{
          background:white;
          padding:25px;
          border-radius:15px;
          box-shadow:0 4px 15px rgba(0,0,0,0.08);
        }

        .action-card button{
          margin-top:10px;
          background:#2563eb;
          color:white;
          border:none;
          padding:10px 20px;
          border-radius:8px;
          cursor:pointer;
        }

        .action-card button:hover{
          background:#1d4ed8;
        }
        `}
      </style>

    </FacultyLayout>

  );
}

export default FacultyDashboard;
